// DuelGrid App.jsx - React-based tactical game with 8 characters, grid movement, and HP display

import React, { useState } from 'react';
import './App.css';

const gridSize = 8;

const initialCharacters = [
  { id: 1, name: 'Knight', hp: 100, atk: 30, x: 0, y: 0, sprite: '/sprites/knight.png', team: 'A' },
  { id: 2, name: 'Archer', hp: 80, atk: 25, x: 1, y: 0, sprite: '/sprites/archer.png', team: 'A' },
  { id: 3, name: 'Mage', hp: 70, atk: 40, x: 2, y: 0, sprite: '/sprites/mage.png', team: 'A' },
  { id: 4, name: 'Healer', hp: 90, atk: 10, x: 3, y: 0, sprite: '/sprites/healer.png', team: 'A' },
  { id: 5, name: 'Warrior', hp: 110, atk: 35, x: 0, y: 7, sprite: '/sprites/warrior.png', team: 'B' },
  { id: 6, name: 'Rogue', hp: 75, atk: 30, x: 1, y: 7, sprite: '/sprites/rogue.png', team: 'B' },
  { id: 7, name: 'Summoner', hp: 65, atk: 45, x: 2, y: 7, sprite: '/sprites/summoner.png', team: 'B' },
  { id: 8, name: 'Paladin', hp: 95, atk: 20, x: 3, y: 7, sprite: '/sprites/paladin.png', team: 'B' },
];

function App() {
  const [characters, setCharacters] = useState(initialCharacters);
  const [selectedId, setSelectedId] = useState(null);

  const moveCharacter = (id, dx, dy) => {
    setCharacters(prev =>
      prev.map(c => {
        if (c.id === id) {
          const newX = Math.max(0, Math.min(gridSize - 1, c.x + dx));
          const newY = Math.max(0, Math.min(gridSize - 1, c.y + dy));
          return { ...c, x: newX, y: newY };
        }
        return c;
      })
    );
  };

  const attack = attackerId => {
    const attacker = characters.find(c => c.id === attackerId);
    const targets = characters.filter(
      c => c.team !== attacker.team && Math.abs(c.x - attacker.x) + Math.abs(c.y - attacker.y) === 1
    );
    if (targets.length > 0) {
      const target = targets[0];
      setCharacters(prev =>
        prev.map(c =>
          c.id === target.id ? { ...c, hp: Math.max(0, c.hp - attacker.atk) } : c
        )
      );
    }
  };

  return (
    <div className="App">
      <h1>DuelGrid</h1>
      <div className="grid">
        {Array.from({ length: gridSize }).map((_, y) => (
          <div key={y} className="row">
            {Array.from({ length: gridSize }).map((_, x) => {
              const char = characters.find(c => c.x === x && c.y === y);
              return (
                <div
                  key={x}
                  className={`tile ${char ? 'occupied' : ''}`}
                  onClick={() => setSelectedId(char?.id)}
                >
                  {char && (
                    <div className="character">
                      <img src={char.sprite} alt={char.name} className="sprite" />
                      <div className="stats">
                        <div>{char.name}</div>
                        <div>HP: {char.hp}</div>
                        <div>ATK: {char.atk}</div>
                      </div>
                    </div>
                  )}
                </div>
              );
            })}
          </div>
        ))}
      </div>
      <div className="controls">
        {selectedId && (
          <>
            <button onClick={() => moveCharacter(selectedId, -1, 0)}>←</button>
            <button onClick={() => moveCharacter(selectedId, 1, 0)}>→</button>
            <button onClick={() => moveCharacter(selectedId, 0, -1)}>↑</button>
            <button onClick={() => moveCharacter(selectedId, 0, 1)}>↓</button>
            <button onClick={() => attack(selectedId)}>Attack</button>
          </>
        )}
      </div>
    </div>
  );
}

export default App;
